import React from 'react';
import { X, CreditCard, Star } from 'lucide-react';

export function WalletModal({ isOpen, onClose, balance, onAddCoins }) {
  if (!isOpen) return null;

  const packages = [
    { coins: 100, stars: 100, price: '100 ⭐' },
    { coins: 500, stars: 450, price: '450 ⭐' },
    { coins: 1000, stars: 850, price: '850 ⭐' },
    { coins: 5000, stars: 4000, price: '4000 ⭐' }
  ];

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
      <div className="bg-white rounded-xl p-6 max-w-md w-full mx-4">
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-xl font-bold">TerriCoin Wallet</h3>
          <button 
            onClick={onClose}
            className="p-2 hover:bg-gray-100 rounded-full transition-colors"
          >
            <X size={24} />
          </button>
        </div>

        <div className="text-center mb-8">
          <p className="text-gray-600 mb-2">Sold curent</p>
          <p className="text-3xl font-bold text-blue-600">{balance} TC</p>
        </div>

        <div className="grid grid-cols-2 gap-4">
          {packages.map((pkg) => (
            <button
              key={pkg.coins}
              onClick={() => onAddCoins(pkg.coins)}
              className="bg-blue-600 text-white p-4 rounded-xl hover:bg-blue-700 transition-colors flex flex-col items-center gap-2"
            >
              <CreditCard size={24} />
              <div className="font-bold">{pkg.coins} TC</div>
              <div className="text-sm flex items-center gap-1">
                <Star size={16} className="fill-yellow-400 text-yellow-400" />
                {pkg.price}
              </div>
              <div className="text-xs text-blue-200">
                {pkg.stars < pkg.coins && `Economisești ${pkg.coins - pkg.stars} ⭐`}
              </div>
            </button>
          ))}
        </div>

        <div className="mt-6 text-center text-sm text-gray-500">
          Notă: Stelele Telegram sunt folosite pentru achiziții
        </div>
      </div>
    </div>
  );
}

export default WalletModal;
